:root {
  --card-bg: #1a2740;
  --card-header-bg: #1e3054;
  --accent-blue: #4a9eff;
  --accent-yellow: #ffd166;
  --text-primary: #ffffff;
  --text-secondary: #8ba3c7;
  --divider-color: #2e4270;
  --today-bg: #2e4a7a;
  --today-border: #4a9eff;
  --day-card-bg: #243352;
  --stat-bg: #243352;
  --high-temp: #ffffff;
  --low-temp: #8ba3c7;
  --border-radius-card: 16px;
  --border-radius-day: 10px;
  --border-radius-stat: 8px;
}

.forecast-card {
  background-color: var(--card-bg);
  border-radius: var(--border-radius-card);
  padding: 20px;
  width: 500px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  background-color: var(--card-header-bg);
  border-radius: var(--border-radius-day);
  padding: 14px 16px;
}

.location {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.city {
  font-size: 20px;
  font-weight: 700;
  color: var(--text-primary);
  line-height: 1.2;
}

.region {
  font-size: 12px;
  font-weight: 400;
  color: var(--text-secondary);
}

.current-temp {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 2px;
}

.temp-value {
  font-size: 32px;
  font-weight: 700;
  color: var(--accent-yellow);
  line-height: 1;
}

.temp-label {
  font-size: 11px;
  font-weight: 500;
  color: var(--text-secondary);
}

.divider {
  height: 1px;
  background-color: var(--divider-color);
}

.forecast-grid {
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: 8px;
}

.day-card {
  background-color: var(--day-card-bg);
  border-radius: var(--border-radius-day);
  padding: 10px 6px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  border: 1px solid transparent;
}

.day-card.today {
  background-color: var(--today-bg);
  border-color: var(--today-border);
}

.day-name {
  font-size: 11px;
  font-weight: 600;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.day-card.today .day-name {
  color: var(--accent-blue);
}

.day-icon {
  font-size: 22px;
  line-height: 1;
}

.day-high {
  font-size: 15px;
  font-weight: 700;
  color: var(--high-temp);
}

.day-low {
  font-size: 12px;
  font-weight: 400;
  color: var(--low-temp);
}

.stats-row {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.stat-item {
  background-color: var(--stat-bg);
  border-radius: var(--border-radius-stat);
  padding: 10px 8px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.stat-label {
  font-size: 10px;
  font-weight: 500;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.stat-value {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-primary);
}
